fixed_code:
use std::fs::File;
use std::io::{BufWriter, Write};

fn main() {
    let mut file = File::create("output.txt").unwrap();
    let mut writer = BufWriter::new(file);
    write!(writer, "Hello, world!").unwrap();
    writer.flush().unwrap();
}

